(() => {
                  const config = sensor.sensor_config || {
                    temperature: { enabled: true },
                    humidity: { enabled: true },
                  };
                  const payload = {};
                  Object.keys(config).forEach((k) => {
                    if (config[k].enabled) payload[k] = 25.0;
                  });
                  return JSON.stringify(payload);
                })

(() => {
            const paramMetadata = {
              temperature: {
                label: "Suhu",
                unit: "°C",
                bg: "rgba(255, 152, 0, 0.08)",
                text: "#e65100",
                border: "rgba(255, 152, 0, 0.2)",
              },
              humidity: {
                label: "Lembab",
                unit: "%",
                bg: "rgba(33, 150, 243, 0.08)",
                text: "#0277bd",
                border: "rgba(33, 150, 243, 0.2)",
              },
              soil_ph: {
                label: "pH Tanah",
                unit: "",
                bg: "rgba(156, 39, 176, 0.08)",
                text: "#6a1b9a",
                border: "rgba(156, 39, 176, 0.2)",
              },
              rainfall: {
                label: "Hujan",
                unit: "mm",
                bg: "rgba(0, 188, 212, 0.08)",
                text: "#006064",
                border: "rgba(0, 188, 212, 0.2)",
              },
              wind_speed: {
                label: "Angin",
                unit: "m/s",
                bg: "rgba(76, 175, 80, 0.08)",
                text: "#33691e",
                border: "rgba(76, 175, 80, 0.2)",
              },
              soil_moisture: {
                label: "Lembab Tanah",
                unit: "%",
                bg: "rgba(63, 81, 181, 0.08)",
                text: "#1a237e",
                border: "rgba(63, 81, 181, 0.2)",
              },
              light_intensity: {
                label: "Cahaya",
                unit: "lux",
                bg: "rgba(255, 235, 59, 0.12)",
                text: "#f57f17",
                border: "rgba(255, 235, 59, 0.3)",
              },
              pressure: {
                label: "Tekanan",
                unit: "hPa",
                bg: "rgba(121, 85, 72, 0.08)",
                text: "#3e2723",
                border: "rgba(121, 85, 72, 0.2)",
              },
            };

            const config = sensor.sensor_config || {};
            const hasConfig = Object.keys(config).length > 0;
            const keys = Object.keys(paramMetadata);
            const dataToShow = keys.filter((key) => {
              if (hasConfig) {
                return config[key] && config[key].enabled;
              }
              return (
                sensor.latest_data[key] !== null &&
                sensor.latest_data[key] !== undefined
              );
            });

            if (dataToShow.length === 0) {
              return (
                <div
                  style={{
                    gridColumn: "1 / -1",
                    textAlign: "center",
                    padding: "1rem",
                    color: "var(--color-text-light)",
                    fontSize: "0.85rem",
                    fontStyle: "italic",
                  }}
                >
                  Tidak ada data aktif
                </div>
              );
            }

            return dataToShow.map((key) => {
              const meta = paramMetadata[key];
              const value = sensor.latest_data[key];
              return (
                <div
                  key={key}
                  style={{
                    background: meta.bg,
                    padding: "1rem",
                    borderRadius: "12px",
                    border: `1px solid ${meta.border}`,
                    display: "flex",
                    flexDirection: "column",
                    gap: "0.4rem",
                    boxShadow: "0 2px 4px rgba(0,0,0,0.02)",
                  }}
                >
                  <div
                    style={{
                      fontSize: "0.75rem",
                      color: meta.text,
                      fontWeight: "800",
                      opacity: 0.8,
                    }}
                  >
                    {meta.label.toUpperCase()}
                  </div>
                  <div
                    style={{
                      fontSize: "1.3rem",
                      fontWeight: "900",
                      color: meta.text,
                      letterSpacing: "-0.5px",
                    }}
                  >
                    {typeof value === "number" ? value.toFixed(1) : value}
                    <span
                      style={{
                        fontSize: "0.85rem",
                        marginLeft: "2px",
                        fontWeight: "600",
                      }}
                    >
                      {meta.unit}
                    </span>
                  </div>
                </div>
              );
            });
          })
